    // --- 2. ALGORITMO DE DISTANCIA DE LEVENSHTEIN ---
    public int calcularDistancia(String s1, String s2) {
        int[][] dp = new int[s1.length() + 1][s2.length() + 1];

        for (int i = 0; i <= s1.length(); i++) dp[i][0] = i;
        for (int j = 0; j <= s2.length(); j++) dp[0][j] = j;

        for (int i = 1; i <= s1.length(); i++) {
            for (int j = 1; j <= s2.length(); j++) {
                int cost = (s1.charAt(i - 1) == s2.charAt(j - 1)) ? 0 : 1;
                dp[i][j] = Math.min(
                    Math.min(dp[i - 1][j] + 1, dp[i][j - 1] + 1), 
                    dp[i - 1][j - 1] + cost
                );
            }
        }
        return dp[s1.length()][s2.length()];
    }

    // --- 3. MÉTODO PARA BUSCAR SUGERENCIA ---
    public String sugerirCorreccion(String lexemaMalEscrito) {
        if (lexemaMalEscrito == null || lexemaMalEscrito.isEmpty()) return "";
        
        String mejorCandidato = null;
        int menorDistancia = 3; 

        for (String kw : KEYWORDS) {
            int dist = calcularDistancia(lexemaMalEscrito.toLowerCase(), kw);
            if (dist < menorDistancia) {
                menorDistancia = dist;
                mejorCandidato = kw;
            }
        }
        
        if (mejorCandidato != null) {
            return " ¿Quisiste decir \"" + mejorCandidato + "\"?";
        }
        return "";
    }

    // --- REPORTE DE ERRORES DE CONTEXTO ---
    public void report_context_error(String mensaje, Object info) {
        int linea = 0;
        int columna = 0;

        if (info instanceof Symbol) {
            Symbol s = (Symbol) info;
            linea = s.left;
            columna = s.right;
        }

        if (linea <= 0 && cur_token != null) {
            linea = cur_token.left;
            columna = cur_token.right;
        }

        if (linea > 0) {
            errores.add("Error en Línea " + linea + ", Columna " + columna + ": " + mensaje);
        } else {
            errores.add("Error de Sintaxis: " + mensaje);
        }
    }

    // --- REPORTE DE ERRORES SEMÁNTICOS ---
    public void reportar_error_semantico(String mensaje, int linea, int columna) {
        erroresSemanticos.add("Error Semántico en Línea " + linea + ", Columna " + columna + ": " + mensaje);
    }

    // --- TRADUCTOR DE TOKEN ---
    private String simboloEnEspanol(int idSimbolo) {
        switch (idSimbolo) {
            case sym.Identificador: return "un identificador";
            case sym.Numero:        return "un número entero";
            case sym.NumeroDecimal: return "un número decimal";
            case sym.CADENA:        return "una cadena de texto";
            case sym.NOTE:          return "una nota musical (do, re, mi...)";
            
            case sym.PuntoComa:     return "un punto y coma ';'";
            case sym.Coma:          return "una coma ','";
            case sym.DosPuntos:     return "dos puntos ':'";
            case sym.Igual:         return "signo igual '='";
            case sym.LlaveAper:     return "llave de apertura '{'";
            case sym.LlaveCierre:   return "llave de cierre '}'";
            case sym.ParenAper:     return "paréntesis de apertura '('";
            case sym.ParenCierre:   return "paréntesis de cierre ')'";
            case sym.CorcheteAper:  return "corchete '['";
            case sym.CorcheteCierre: return "corchete ']'";
            
            case sym.Suma: case sym.Resta: case sym.Multiplicacion: case sym.Division: 
                return "un operador aritmético";
            
            case sym.KW_VECES:      return "palabra 'veces'";
            case sym.KW_FIN:        return "palabra 'fin'";
            case sym.KW_SECCION:    return "palabra 'seccion'";
            case sym.KW_TRUE:       return "valor 'true'";
            case sym.KW_FALSE:      return "valor 'false'";
            case sym.KW_LEER:       return "palabra 'leer'";
            
            case sym.EOF:           return "fin de archivo";
            case sym.error:         return "error";
            
            default: return "token desconocido (ID: " + idSimbolo + ")";
        }
    }

    // --- LÓGICA MAESTRA DE ERRORES AUTOMÁTICOS ---
    @Override
    public void syntax_error(Symbol s) {
        if (!errores.isEmpty()) {
            String ultimo = errores.get(errores.size() - 1);
            if (ultimo.contains("Línea " + s.left)) return;
        }

        String lexema = (s.value != null) ? s.value.toString() : "token desconocido";
        int linea = (s.left > 0) ? s.left : (cur_token != null ? cur_token.left : 0);
        int columna = (s.right > 0) ? s.right : (cur_token != null ? cur_token.right : 0);
        
        StringBuilder msg = new StringBuilder();
        msg.append("Error en Línea ").append(linea).append(", Columna ").append(columna);
        msg.append(": Se encontró \"").append(lexema).append("\"");

        try {
            List<Integer> esperados = expected_token_ids();
            
            if (s.sym == sym.Identificador) {
                msg.append(sugerirCorreccion(lexema));
            }

            if (esperados.contains(sym.PuntoComa)) {
                msg.append(", pero FALTA UN PUNTO Y COMA ';' antes de esto.");
            } 
            else if (esperados.contains(sym.DosPuntos)) {
                msg.append(", pero FALTAN DOS PUNTOS ':' (ej: seccion: o caso 1:).");
            }
            else if (esperados.contains(sym.LlaveCierre)) {
                msg.append(", pero falta cerrar un BLOQUE con LLAVE '}'.");
            }
            else if (esperados.contains(sym.ParenCierre)) {
                msg.append(", pero falta cerrar un PARÉNTESIS ')'.");
            }
            else if (esperados.contains(sym.Igual) && s.sym == sym.ParenAper) {
                msg.append(". Pareces llamar a una función, pero esa instrucción no existe o no es válida aquí.");
            }
            else if (!esperados.isEmpty()) {
                msg.append(", pero se esperaba: ");
                boolean primero = true;
                int max = 0;
                for (int id : esperados) {
                    if (id == sym.error) continue;
                    if (max++ > 4) break; 
                    if (!primero) msg.append(" o ");
                    msg.append(simboloEnEspanol(id));
                    primero = false;
                }
            } else {
                msg.append(" en una posición inválida.");
            }
        } catch (Exception e) {
            msg.append(".");
        }
        errores.add(msg.toString());
    }

    @Override
    public void unrecovered_syntax_error(Symbol s) throws java.lang.Exception {
        if (errores.isEmpty()) {
            errores.add("Error Fatal: Estructura incompleta. Revise si faltan llaves '}' o la instrucción 'fin'.");
        }
    }


